<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller; use App\Http\Requests\Admin\{BookingRequest,SeatHoldRequest}; use App\Models\{Booking,Nationality,TravelSchedule}; use App\Services\Admin\{BookingService,SeatService};
class BookingController extends Controller { public function index(){ $this->authorize('manage',Booking::class); return view('admin.bookings.index',['bookings'=>Booking::with('passenger','route','schedule','seats')->latest()->paginate(15)]); } public function create(){ $this->authorize('manage',Booking::class); return view('admin.bookings.form',['schedules'=>TravelSchedule::with('route')->where('status','scheduled')->get(),'nationalities'=>Nationality::where('status','active')->get()]); } public function store(BookingRequest $r, BookingService $s){ $booking=$s->create($r->validated(),$r->user()->id); return redirect()->route('admin.bookings.show',$booking); } public function show(Booking $booking){ $this->authorize('manage',Booking::class); return view('admin.bookings.show',['booking'=>$booking->load('passenger.nationality','route','schedule','returnSchedule','seats')]); } public function seats(TravelSchedule $schedule, SeatService $s){ $this->authorize('manage',Booking::class); return response()->json($s->availability($schedule->load('seatLayout.seats'))); } public function hold(SeatHoldRequest $r, SeatService $s){ $schedule=TravelSchedule::findOrFail($r->travel_schedule_id); return response()->json(['token'=>$s->hold($schedule,$r->seat_ids,$r->user()->id),'expires_at'=>now()->addMinutes(15)->toDateTimeString()]); } }
